Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <CollectionView.RefreshCommand>
            <Binding Path="RefreshCommand" />
        </CollectionView.RefreshCommand>

        <!-- Wrap in a RefreshView for pull-to-refresh -->
    </CollectionView>
</ContentPage>
```

Actually, `CollectionView` doesn't directly support pull-to-refresh — you need to wrap it in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <Grid Padding="10">
                    <Label Text="{Binding Name}" FontSize="16" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    private Item? _selectedItem;
    public Item? SelectedItem
    {
        get => _selectedItem;
        set
        {
            if (SetProperty(ref _selectedItem, value) && value is not null)
            {
                // Navigate, then clear selection so the user can re-select
                GoToDetailAsync(value).FireAndForget();
                SelectedItem = null;
            }
        }
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }

    private async Task GoToDetailAsync(Item item)
    {
        await Shell.Current.GoToAsync(
            nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = item });
    }
}
```

**Key binding points:**

| ViewModel property | Bound to | Purpose |
|---|---|---|
| `Items` | `CollectionView.ItemsSource` | Data source |
| `SelectedItem` (TwoWay) | `CollectionView.SelectedItem` | Triggers navigation on tap, reset to `null` to allow re-selection |
| `IsRefreshing` | `RefreshView.IsRefreshing` | Set to `false` when load finishes to dismiss the spinner |
| `RefreshCommand` | `RefreshView.Command` | Calls your API and replaces the collection |

**Important details:**
- **`RefreshView` wraps `CollectionView`** — the `CollectionView` itself has no refresh support.
- **`Mode=TwoWay`** on `SelectedItem` is required so the VM can clear it back to `null`.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always stops, even on errors.
- Register the `DetailPage` route in `AppShell` with `Routing.RegisterRoute(nameof(DetailPage), typeof(DetailPage))`.
